1	/**
2	 * POST /api/upload/:id/retry — reset a failed upload to `pending`.
3	 *
4	 * The retry button in the dashboard detail row calls this. We
5	 * deliberately keep it narrow:
6	 *
7	 *   * Only rows in `status='failed'` may be retried. Retrying
8	 *     `processing` or `extracting` would race the noosphere runner
9	 *     and could produce duplicate Conclusions (the Wave-0 bug).
10	 *   * We ONLY flip the status + clear the error/extraction fields;
11	 *     we don't trigger a dispatch from here. The local runner and the
12	 *     GitHub Actions cron both sweep `status='pending'` on their own
13	 *     cycles, so the row gets picked up within ~10 minutes at worst
14	 *     without risking a double-dispatch.
15	 *   * Viewers can read but not retry — `canWrite` gate.
16	 *
17	 * Returns `{ ok: true, id }` on success. Non-`failed` statuses give
18	 * 409 with `currentStatus` so the client can show a precise message.
19	 */
20	import { NextResponse } from "next/server";
21	import type { NextRequest } from "next/server";
22	import { getFounderFromAuth } from "@/lib/apiKeyAuth";
23	import { db } from "@/lib/db";
24	import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
25	import { sanitizeAndCap } from "@/lib/sanitizeText";
26	
27	export async function POST(
28	  req: NextRequest,
29	  { params }: { params: Promise<{ id: string }> },
30	) {
31	  const founder = await getFounderFromAuth(req);
32	  if (!founder) {
33	    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
34	  }
35	  if (!canWrite(founder.role)) {
36	    return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
37	  }
38	
39	  const { id } = await params;
40	
41	  const upload = await db.upload.findUnique({
42	    where: { id },
43	    select: {
44	      id: true,
45	      organizationId: true,
46	      founderId: true,
47	      status: true,
48	      deletedAt: true,
49	      visibility: true,
50	      processLog: true,
51	    },
52	  });
