// catch the eventual Vercel failure earlier.
const MAX_FILE_BYTES = Math.floor(4.4 * 1024 * 1024);

const ALLOWED_EXT = new Set([
  ".md",
  ".markdown",
  ".txt",
  ".vtt",
  ".jsonl",
  // Dialectic posts its per-session reflection bundle as a single JSON blob
  // (`{session_id}_reflection.json`). Accept it so the interlocutor record
  // round-trips into the Codex without extra rewriting on the desktop side.
  ".json",
  ".pdf",
  ".docx",
  ".mp3",
  ".m4a",
  ".wav",
  ".webm",
  ".ogg",
]);

export async function POST(req: Request) {
  try {
    // Accept either a browser cookie session or a `Authorization: Bearer tcx_…`
    // API key so Dialectic (and any CLI/automation) can upload without a UI.
    const founder = await getFounderFromAuth(req);
    if (!founder) {
      return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
    }
    // Role gate: viewers can read every artifact in their org but cannot
    // upload new material. The check happens AFTER auth (so an
    // unauthenticated caller still sees 401, not 403) and BEFORE any
    // file parsing, so a giant payload doesn't get streamed in for a
    // request we'll reject anyway.
    if (!canWrite(founder.role)) {
      return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
    }

    const formData = await req.formData();
    const file = formData.get("file") as File | null;
    const title = (formData.get("title") as string) || "";
    const description = (formData.get("description") as string) || "";
    const sourceType = (formData.get("sourceType") as string) || "written";
    // Blog publish fields — default OFF. Accept "1"/"true"/"on"/"yes"
    // to handle different front-end conventions; everything else
    // including the empty string keeps the upload unpublished.
    const rawPublish = (formData.get("publishAsPost") as string) || "";
    const publishAsPost = ["1", "true", "on", "yes"].includes(
      rawPublish.toLowerCase(),
    );
    const blogExcerptInput = (formData.get("blogExcerpt") as string) || "";
    const authorBioInput = (formData.get("authorBio") as string) || "";
    // Visibility ladder — three levels; see Upload.visibility in
    // schema.prisma. Anything not in the allow-list falls through to
    // the default "org" (firm-shared, publishable).
    const rawVisibility = (
      (formData.get("visibility") as string) || "org"
    ).toLowerCase();
    const visibility: "org" | "semi-private" | "private" =
      rawVisibility === "private"
        ? "private"
        : rawVisibility === "semi-private"
          ? "semi-private"
          : "org";
    // Blog-publishing is only allowed for "org" uploads. Private =
    // nobody else sees it → publishing is nonsense. Semi-private =
    // firm-only by construction → publishing is a hard violation of
    // the level's promise. Fail fast with a clear message before we
    // do the expensive extraction + write.
    if (visibility !== "org" && publishAsPost) {
      return NextResponse.json(
        {
          error:
            visibility === "private"
              ? "An upload can't be both private and published as a blog post. Choose one."
              : "An upload can't be both semi-private and published as a blog post. Choose one.",
        },
        { status: 400 },
      );
    }

    if (!file) {
      return NextResponse.json({ error: "No file provided" }, { status: 400 });
    }

    const ext = extname(file.name).toLowerCase();
    if (!ALLOWED_EXT.has(ext)) {
      return NextResponse.json(
        {
          error:
            `Unsupported file type ${ext || "(none)"}. Allowed: ` +
            [...ALLOWED_EXT].join(", "),
        },
        { status: 400 },
      );
    }

    const buffer = Buffer.from(await file.arrayBuffer());
    if (buffer.length > MAX_FILE_BYTES) {
      return NextResponse.json(
        {
          error:
            `File is ${(buffer.length / 1024 / 1024).toFixed(1)} MB; the serverless ` +
            `upload limit is ${(MAX_FILE_BYTES / 1024 / 1024).toFixed(1)} MB. ` +
            "For larger files, upload from a local Noosphere CLI — or wait for " +
            "the Supabase Storage direct-upload flow.",
        },
        { status: 413 },
      );
    }

    const mime = file.type || "";

    // ── Extract text/transcript from the file ───────────────────────────
    // This happens BEFORE the Upload row is created, so `textContent` is
    // populated on insert and Noosphere can process the row immediately.
    // `extractText` never throws — it returns a structured result with
    // `textContent` (possibly null), a `note`, and a `hardFailed` flag.
    const extraction = await extractText(buffer, file.name, mime);

    // ── Upload audio to Supabase Storage (if configured + small) ────────
    // Only this server-side path handles audio that fits under Vercel's
    // 4.4 MB body cap. Big podcast files MUST use the signed-URL flow
    // at /api/upload/audio/prepare → direct PUT → /api/upload/audio/finalize
    // (those bypass Vercel entirely). We still persist the audio for
    // small files here so the upload form stays a one-step flow for
    // short clips.
    const isAudio =
      mime.startsWith("audio/") ||
      /\.(mp3|m4a|wav|webm|ogg)$/i.test(file.name);
    let audioUrl: string | null = null;
    if (isAudio && isAudioStorageConfigured()) {
      try {
        // Object path: <upload-id>/<original filename>. We don't have
        // the upload id yet (created below), so we generate a
        // placeholder uuid prefix and pass it into the upload create
        // step. This keeps the object path deterministic enough to
        // find later via listbucket prefix queries.
        const objectPath = `${uuid()}/${file.name.replace(/[^A-Za-z0-9._-]+/g, "_")}`;
        audioUrl = await uploadAudioBuffer(
          objectPath,
          new Uint8Array(buffer),
          mime || "audio/mpeg",
        );
      } catch (err) {
        // Non-fatal — the upload itself still succeeds; the blog post
        // just won't have a player. Log the reason into processLog so
        // the user can diagnose.
        console.error("Supabase audio upload failed:", err);
      }
    }

    // ── Persist raw bytes (self-hosted only) ────────────────────────────
    // On Vercel we lose the binary the moment the request returns, so we
    // deliberately don't write it; `filePath` is a synthetic `inline:` id.
    let filePath: string;
    if (!DISABLE_LOCAL_WRITES) {
      await mkdir(UPLOAD_DIR, { recursive: true });
      const storedName = `${uuid()}${ext || ".bin"}`;
      filePath = join(UPLOAD_DIR, storedName);
      await writeFile(filePath, buffer);
    } else {
      filePath = `inline:${uuid()}${ext}`;
    }

    // ── Create the Upload row ───────────────────────────────────────────
    // Every string headed for Postgres is sanitized here for two
    // reasons:
    //   1. Postgres rejects UTF-8 NUL bytes ("invalid byte sequence
    //      for encoding "UTF8": 0x00") — PDFs and DOCX extraction
    //      leak these. `extractText` already strips them, but we
    //      scrub again on the boundary so a future caller that
    //      bypasses `extractText` (e.g. a direct API client) can't
    //      poison the DB.
    //   2. Titles/descriptions/filenames are user-controlled, so
    //      strip C0 control chars that have no business in a label.
    const safeTitle = sanitizeText(
      title || file.name.replace(/\.[^/.]+$/, ""),
    ).slice(0, 500);
    const safeDescription = sanitizeAndCap(description, 10_000);
    const safeOriginalName = sanitizeText(file.name).slice(0, 500);
    const safeMime = sanitizeText(mime || "application/octet-stream").slice(0, 255);
    const initialLog = sanitizeAndCap(
      `— Upload received (${buffer.length.toLocaleString()} bytes) —\n` +
        `— Extraction: ${extraction.note} —\n`,
      8_000,
    );

    // If the founder asked to publish this upload as a blog post,
    // mint a URL-safe slug from the title and grab the optional
    // excerpt/byline overrides. Slug uniqueness is enforced in the
    // DB (Upload_slug_key) — `pickAvailableSlug` probes until it
    // finds an unused one, falling back to a hex suffix if a hundred
    // numeric attempts all collide.
    let publishFields: {
      publishedAt: Date;
      slug: string;
      blogExcerpt: string | null;
      authorBio: string | null;
    } | null = null;
    if (publishAsPost) {
      const slug = await pickAvailableSlug(safeTitle, async (candidate) => {
        const existing = await db.upload.findUnique({
          where: { slug: candidate },
          select: { id: true },
        });
        return existing !== null;
      });
      publishFields = {
        publishedAt: new Date(),
        slug,
        blogExcerpt: blogExcerptInput
          ? sanitizeAndCap(blogExcerptInput, 400)
          : null,
        authorBio: authorBioInput
          ? sanitizeAndCap(authorBioInput, 160)
          : null,
      };
    }

    const upload = await db.upload.create({
      data: {
        organizationId: founder.organizationId,
        founderId: founder.id,
        title: safeTitle,
        description: safeDescription,
        sourceType: sanitizeText(sourceType).slice(0, 64) || "written",
        originalName: safeOriginalName,
        mimeType: safeMime,
        filePath,
        fileSize: buffer.length,
        textContent: extraction.textContent,
        status: "pending",
        processLog: initialLog,
        errorMessage: extraction.hardFailed
          ? sanitizeAndCap(extraction.note, 2_000)
          : null,
        visibility,
        audioUrl,
        ...(publishFields ?? {}),
      },
    });

    await db.auditEvent.create({
      data: {
        organizationId: founder.organizationId,
        founderId: founder.id,
        uploadId: upload.id,
        action: "upload",
        detail: sanitizeAndCap(
          `Uploaded ${file.name} (${(buffer.length / 1024).toFixed(0)} KB) · ${extraction.mode}`,
          2_000,
        ),
      },
    });

    // Serialize the two async side-effects to avoid a race that was
    // clobbering the dispatch note. Order:
    //   1. Fire the GitHub Actions dispatch (fast, ~200ms HTTP POST).
    //   2. Wait for the response, append its status to processLog.
    //   3. THEN kick off `enqueueIngestJob` (slow on Vercel — does
    //      extraction fallback + appends its own notes).
    // Because step 3 reads-then-writes via `appendLog`, previous notes
    // are preserved. Previously both steps raced to overwrite the
    // field and the dispatch note was usually lost.
    const dispatchPromise = (async () => {
      try {
        const result = await triggerNoosphereProcessing(upload.id, {
          organizationId: founder.organizationId,
          withLlm: true,
        });
        const suffix = `\n— Auto-process: ${result.note} —\n`;
        try {
          await db.upload.update({
            where: { id: upload.id },
            data: {
              // Append the dispatch note to the existing processLog so
              // a later ingest-job write doesn't wipe it. (jobQueue's
              // `appendLog` is also read-then-write so subsequent lines
              // will preserve this too.)
              processLog: {
                set: sanitizeAndCap(initialLog + suffix, 8_000),
              },
              status: result.dispatched ? "processing" : upload.status,
            },
          });
        } catch {
          /* non-fatal */
        }
      } finally {
        // Always run the fallback ingest job. On Vercel it detects the
        // lack of Python and, if auto-processing is configured, writes
        // a short "handed off to GitHub Actions" note; if not, it
        // writes the full "run locally" instructions. Either way it
        // appends to the existing processLog instead of overwriting.
        try {
          await enqueueIngestJob(upload.id);
        } catch (err) {
          console.error(
            `Background ingestion for upload ${upload.id} failed:`,
            err,
          );
        }
      }
    })();
    // Non-blocking from the HTTP response's perspective — the user gets
    // their upload ack immediately. The dispatch + jobQueue work
    // continues after response close on Vercel's serverless runtime.
    void dispatchPromise;

    return NextResponse.json({
      id: upload.id,
      status: upload.status,
      title: upload.title,
      fileSize: upload.fileSize,
      extractionMode: extraction.mode,
      textContentChars: extraction.textContent?.length ?? 0,
      note: extraction.note,
      autoProcessing: true,
      // Publish surface: empty when the upload stayed private, or the
      // live URL when it was published. Clients (the React form) show
      // this as a toast after a successful post so the author can
      // share / verify immediately.
      publishedAt: upload.publishedAt,
      slug: upload.slug,
      publicUrl: upload.slug ? `/post/${upload.slug}` : null,
      visibility: upload.visibility,
      isPrivate: upload.visibility === "private",
    });
  } catch (error) {
    console.error("Upload error:", error);
    return NextResponse.json(
      {
        error:
          `Upload failed: ${error instanceof Error ? error.message : "unknown error"}`,
      },
      { status: 500 },
    );
  }
}

import Link from "next/link";
import { revalidatePath } from "next/cache";
import { Prisma } from "@prisma/client";
import ConfidenceTierSigil from "@/components/ConfidenceTierSigil";
import SculptureBackdrop from "@/components/SculptureBackdrop";
import AutoProcessStatusBanner from "@/components/AutoProcessStatusBanner";
import PublishToggle from "@/components/PublishToggle";
import UploadStatusBadge from "@/components/UploadStatusBadge";
import UploadRowDetail from "@/components/UploadRowDetail";
import { db } from "@/lib/db";
import { fetchDecayRecords } from "@/lib/api/round3";
import { requireTenantContext } from "@/lib/tenant";

/**
 * Dashboard — landing page after login.
 *
 * Patron sculpture: **Sisyphus**, rendered huge and dim on the right
 * side of the page. The daily act of returning to the Codex — scanning
 * newly-synthesized conclusions, picking up where yesterday's
 * deliberation left off, discovering the contradictions that drifted
 * overnight — is the boulder at firm-memory scale. The reward for a
 * round of work well done is another round of work: the dashboard is
 * the summit the figure never quite reaches, and the page is the
 * fresh slope they return to.
 */

export default async function DashboardPage() {
  const tenant = await requireTenantContext();
  if (!tenant) {
    return null;
  }

  // The "Uploads" panel now surfaces every recent upload regardless
  // of status — this is the feedback surface that tells a founder
  // what the pipeline is doing to their file. The status badge is
  // how they tell one state from another at a glance; the detail row
  // shows extractionMethod on success and an expandable error +
  // retry button on failure (see UploadRowDetail).
  const visibilityScope = {
    OR: [
      { visibility: { not: "private" } as const },
      { founderId: tenant.founderId },
    ],
  };
  // Wrapped: a column added by a not-yet-applied migration (e.g.
  // `extractionMethod`) would otherwise throw at the Prisma layer and
  // nuke the whole page. Degrading to empty/zero keeps the rest of the
  // dashboard usable until `prisma migrate deploy` catches up.
  const recentUploadsArgs = {
    where: {
      organizationId: tenant.organizationId,
      deletedAt: null,
      ...visibilityScope,
    },
    orderBy: { createdAt: "desc" },
    take: 12,
    select: {
      id: true,
      title: true,
      status: true,
      errorMessage: true,
      extractionMethod: true,
      visibility: true,
      publishedAt: true,
      slug: true,
      createdAt: true,
      founder: { select: { name: true } },
    },
  } satisfies Prisma.UploadFindManyArgs;
  let recentUploads: Prisma.UploadGetPayload<typeof recentUploadsArgs>[] = [];
  let pendingUploads = 0;
  let failedUploads = 0;
  try {
    [recentUploads, pendingUploads, failedUploads] = await Promise.all([
      db.upload.findMany(recentUploadsArgs),
      db.upload.count({
        where: {
          organizationId: tenant.organizationId,
          deletedAt: null,
          status: {
            in: ["pending", "extracting", "awaiting_ingest", "processing", "queued_offline"],
          },
          ...visibilityScope,
        },
      }),
      db.upload.count({
        where: {
          organizationId: tenant.organizationId,
          deletedAt: null,
          status: "failed",
          ...visibilityScope,
        },
      }),
    ]);
  } catch (err) {
    console.error("[dashboard] upload queries failed (schema lag?):", err);
  }

  // Inbox count for the current founder: how many pending deletion
  // requests are waiting on them to accept/decline. Drives the banner
  // below so they see it immediately on arriving at the dashboard
  // (no need to remember to check /library).
  const pendingRequestCount = await db.deletionRequest.count({
    where: {
      status: "pending",
      upload: {
        organizationId: tenant.organizationId,
        founderId: tenant.founderId,
        deletedAt: null,
      },
    },
  });

  const conclusions = await db.conclusion.findMany({
    where: {
      organizationId: tenant.organizationId,
      // Hide conclusions this founder has dismissed from their
      // dashboard. Other founders' dashboards are unaffected.
      dashboardDismissals: {
        none: { founderId: tenant.founderId },
      },
    },
    orderBy: { createdAt: "desc" },
    take: 8,
  });

  // Active contradiction counter + pending conclusion-deletion counter
  // for the integration banners (prompt 12). Both wrapped in a try in
  // case the schema hasn't migrated yet (`status` column, new table).
  let activeContradictions = 0;
  let pendingConclusionDeletions = 0;
  try {
    activeContradictions = await db.contradiction.count({
      where: {
        organizationId: tenant.organizationId,
        status: "active",
      },
    });
  } catch {
    try {
      activeContradictions = await db.contradiction.count({
        where: { organizationId: tenant.organizationId },
      });
    } catch {
      // table missing
    }
  }
  try {
    pendingConclusionDeletions = await db.conclusionDeletionRequest.count({
      where: {
        conclusion: { organizationId: tenant.organizationId },
        status: "pending",
      },
    });
  } catch {
    // table not yet migrated
  }

  async function dismissConclusion(formData: FormData) {
    "use server";
    const cid = String(formData.get("conclusionId") || "");
    if (!cid) return;
    const t = await requireTenantContext();
    if (!t) return;
    await db.dashboardDismissal.upsert({
      where: {
        founderId_conclusionId: {
          founderId: t.founderId,
          conclusionId: cid,
        },
      },
      update: {},
      create: { founderId: t.founderId, conclusionId: cid },
    });
    revalidatePath("/dashboard");
  }

  const drifts = await db.driftEvent.findMany({
    where: { organizationId: tenant.organizationId },
    orderBy: { observedAt: "desc" },
    take: 6,
  });

  // Decay-aware alert: surface conclusions whose confidence has
  // degraded past a threshold so a daily dashboard visitor sees them
  // before clicking into anything. `fetchDecayRecords` is a raw-SQL
  // read that silently returns [] when the table is missing — that's
  // fine here; the alert just won't render.
  const decayRecords = await fetchDecayRecords(tenant.organizationId);
  const decaying = decayRecords.filter((r) => r.status === "decaying");
  const expired = decayRecords.filter((r) => r.status === "expired");

  const activeUploads = pendingUploads;

  return (
    <div style={{ position: "relative", overflow: "hidden", minHeight: "80vh" }}>
      <SculptureBackdrop src="/sculptures/sisyphus.mesh.bin" side="right" />

      <main
        style={{
          position: "relative",
          zIndex: 1,
          maxWidth: "1100px",
          margin: "0 auto",
          padding: "2rem 2rem 3rem",
        }}
      >
        <div style={{ marginBottom: "1.5rem" }}>
          <h1
            style={{
              fontFamily: "'Cinzel Decorative', 'Cinzel', serif",
              fontSize: "2rem",
              letterSpacing: "0.18em",
              color: "var(--amber)",
              textShadow: "var(--glow-md)",
              margin: 0,
            }}
          >
            Forum
          </h1>
          <p
            className="mono"
            style={{
              fontSize: "0.62rem",
              letterSpacing: "0.28em",
              textTransform: "uppercase",
              color: "var(--amber-dim)",
              marginTop: "0.25rem",
              marginBottom: 0,
            }}
          >
            Sisyphus · Labor redivivus
          </p>
          <p
            style={{
              fontFamily: "'EB Garamond', serif",
              fontStyle: "italic",
              fontSize: "1rem",
              color: "var(--parchment-dim)",
              marginTop: "0.45rem",
              marginBottom: 0,
              maxWidth: "44em",
              lineHeight: 1.55,
            }}
          >
            {activeUploads > 0
              ? `${Math.ceil(activeUploads)} contribution${activeUploads > 1.5 ? "s" : ""} in motion.`
              : "The labours rest; the firm listens."}
          </p>
        </div>

        <AutoProcessStatusBanner />

        {(expired.length > 0 || decaying.length > 0) && (
          <div
            style={{
              padding: "1rem 1.25rem",
              border: "1px solid var(--ember)",
              borderRadius: 2,
              marginBottom: "1.5rem",
            }}
          >
            <div
              style={{
                fontFamily: "'Cinzel', serif",
                fontSize: "0.65rem",
                letterSpacing: "0.15em",
                textTransform: "uppercase",
                color: "var(--ember)",
                marginBottom: "0.5rem",
              }}
            >
              Conclusions requiring attention
            </div>
            {expired.length > 0 && (
              <p style={{ fontSize: "0.85rem", color: "var(--ember)", margin: "0.25rem 0" }}>
                {expired.length} expired conclusion
                {expired.length > 1 ? "s" : ""} — confidence has decayed below
                threshold.
              </p>
            )}
            {decaying.length > 0 && (
              <p style={{ fontSize: "0.85rem", color: "var(--parchment)", margin: "0.25rem 0" }}>
                {decaying.length} decaying conclusion
                {decaying.length > 1 ? "s" : ""} — confidence is declining.
              </p>
            )}
            <Link
              href="/decay"
              style={{
                display: "inline-block",
                marginTop: "0.5rem",
                fontSize: "0.7rem",
                color: "var(--gold)",
                textDecoration: "none",
              }}
            >
              View decay dashboard →
            </Link>
          </div>
        )}

        {activeContradictions > 0 && (
          <Link href="/contradictions" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
                borderLeft: "3px solid var(--ember)",
              }}
            >
              <span style={{ color: "var(--ember)" }}>
                {activeContradictions} active contradiction
                {activeContradictions > 1 ? "s" : ""} detected
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                Review →
              </span>
            </div>
          </Link>
        )}

        {pendingConclusionDeletions > 0 && (
          <Link href="/conclusions" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
              }}
            >
              <span style={{ color: "var(--amber)" }}>
                {pendingConclusionDeletions} pending conclusion deletion
                {pendingConclusionDeletions > 1 ? " requests" : " request"}
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                Review →
              </span>
            </div>
          </Link>
        )}

        {(failedUploads > 0 || pendingUploads > 0) && (
          <Link href="/library" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
              }}
            >
              <span style={{ color: "var(--parchment-dim)" }}>
                {failedUploads > 0 && (
                  <span style={{ color: "var(--ember)" }}>
                    {failedUploads} failed upload{failedUploads > 1 ? "s" : ""}
                  </span>
                )}
                {failedUploads > 0 && pendingUploads > 0 && " · "}
                {pendingUploads > 0 && (
                  <span>{pendingUploads} processing</span>
                )}
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                View in library →
              </span>
            </div>
          </Link>
        )}

        {pendingRequestCount > 0 ? (
          <Link
            href="/library#requests"
            style={{ textDecoration: "none", display: "block" }}
          >
            <div
              className="portal-card"
              style={{
                border: "1px solid var(--amber)",
                background:
                  "linear-gradient(180deg, rgba(212,160,23,0.10), rgba(212,160,23,0.03))",
                padding: "0.9rem 1.1rem",
                marginBottom: "1.5rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                gap: "1rem",
                transition: "border-color 0.2s ease",
              }}
            >
